={
  "from": "Hudson Digital Solutions <hello@hudsondigitalsolutions.com>",
  "to": ["{{ $('Code: Generate Invoice HTML').item.json.client_email }}"],
  "subject": "Invoice {{ $('Code: Generate Invoice HTML').item.json.invoice_number }} from Hudson Digital Solutions",
  "html": "<div style='font-family: system-ui, sans-serif; max-width: 600px;'><h2 style='color: #00D9FF;'>Invoice Ready</h2><p>Hi {{ $('Code: Generate Invoice HTML').item.json.client_name }},</p><p>Thank you for your business! Your invoice is attached to this email.</p><p><strong>Invoice Number:</strong> {{ $('Code: Generate Invoice HTML').item.json.invoice_number }}<br><strong>Amount Due:</strong> ${{ $('Code: Generate Invoice HTML').item.json.total_amount }}<br><strong>Due Date:</strong> {{ $('Code: Generate Invoice HTML').item.json.due_date }}</p><p>You can make payment via:</p><ul><li>Bank transfer (details in invoice)</li><li>Online payment: <a href='https://hudsondigitalsolutions.com/pay/{{ $('Code: Generate Invoice HTML').item.json.invoice_number }}'>Click here to pay</a></li></ul><p>If you have any questions, please don't hesitate to contact us.</p><p>Best regards,<br>Richard Hudson<br>Hudson Digital Solutions<br>hello@hudsondigitalsolutions.com</p></div>",
  "attachments": [
    {
      "filename": "{{ $('Code: Generate Invoice HTML').item.json.invoice_number }}.pdf",
      "content": "{{ $('Stirling-PDF: Convert to PDF').item.binary.data.data }}"
    }
  ]
}

